SELECT

FROM
    CARD_INPUT ci
LEFT JOIN CARD_OUTPUT co ON ci.TSTM_YMD = co.TSTM_YMD
    AND ci.TSTM_NO = co.TSTM_NO
    AND ci.BRCD = co.BRCD
WHERE ci.BRCD is not null
    AND ci.TSTM_YMD = #{tstmYmd}
    AND ci.TSTM_NO = #{tstmNo}
    AND ci.BRCD = #{brcd}
